options {
  server = server;
  exit = exit;
}

contract Endpoint(
  bytes32 endpointCtrlAssetId,
  bytes32 endpointIDAssetId,
  bytes32 oappCtrlAssetId,
  bytes32 oappIDAssetId,
  bytes32 endpointID,
  bytes32 oappID,
  int     remoteEID,
  bytes32 remoteOApp,
  pubkey  dvn0Pk,
  pubkey  dvn1Pk,
  int     exit
) {

  function receive(bytes32 receiveMarkerScriptHash) {
    require(size(tx.packet(16)) == 183, "endpoint state packet size");
    require(size(tx.packet(17)) == 219, "lz receive packet size");
    require(size(tx.packet(18)) == 228, "dvn attestation packet size");

    require(substr(tx.packet(16), 0, 1) == 1, "endpoint state version");
    require(substr(tx.packet(17), 0, 1) == 1, "lz receive version");
    require(substr(tx.packet(18), 0, 1) == 1, "dvn attestation version");

    require(substr(tx.packet(16), 1, 32)  == endpointID, "wrong endpointID");
    require(substr(tx.packet(16), 33, 32) == oappID, "wrong oappID");
    require(bin2num(substr(tx.packet(16), 65, 4)) == remoteEID, "wrong remoteEID");
    require(substr(tx.packet(16), 69, 32) == remoteOApp, "wrong remoteOApp");

    require(bin2num(substr(tx.packet(16), 101, 1)) == 2, "dvn threshold != 2");
    require(bin2num(substr(tx.packet(16), 102, 1)) == 2, "dvn count != 2");
    require(substr(tx.packet(16), 103, 32) == dvn0Pk, "endpoint state dvn0 mismatch");
    require(substr(tx.packet(16), 135, 32) == dvn1Pk, "endpoint state dvn1 mismatch");

    require(substr(tx.packet(17), 1, 32)  == oappID, "lz receiver != oapp");
    require(bin2num(substr(tx.packet(17), 33, 4)) == remoteEID, "lz srcEID != remote");
    require(substr(tx.packet(17), 37, 32) == remoteOApp, "lz sender != remoteOApp");

    require(bin2num(substr(tx.packet(18), 33, 1)) == 2, "dvn count != 2");
    require(bin2num(substr(tx.packet(18), 34, 1)) == 0, "dvn att0 index != 0");
    require(bin2num(substr(tx.packet(18), 131, 1)) == 1, "dvn att1 index != 1");
    require(substr(tx.packet(18), 35, 32) == dvn0Pk, "dvn att0 pk mismatch");
    require(substr(tx.packet(18), 132, 32) == dvn1Pk, "dvn att1 pk mismatch");
    require(
      sha256(substr(tx.packet(17), 1, 140)) == attestedHash,
      "attested hash does not match lz receive header"
    );
    require(substr(tx.packet(18), 1, 32) == attestedHash, "dvn attested hash mismatch");

    require(checkSigFromStackVerify(dvn0Sig, dvn0Pk, attestedHash), "dvn0 sig invalid");
    require(checkSigFromStackVerify(dvn1Sig, dvn1Pk, attestedHash), "dvn1 sig invalid");

    require(
      sha256(substr(tx.packet(17), 145, 74)) == substr(tx.packet(17), 109, 32),
      "credit message hash mismatch"
    );

    require(
      tx.outputs[0].scriptPubKey == new Endpoint(
        endpointCtrlAssetId, endpointIDAssetId,
        oappCtrlAssetId,     oappIDAssetId,
        endpointID, oappID, remoteEID, remoteOApp,
        dvn0Pk, dvn1Pk, exit
      ),
      "endpoint state must continue"
    );
    require(
      tx.outputs[0].assets.lookup(endpointCtrlAssetId) == 1,
      "endpoint control missing on next state"
    );

    require(
      tx.outputs[1].assets.lookup(endpointIDAssetId) == 1,
      "marker asset missing"
    );
    require(
      tx.outputs[1].scriptPubKey == new ReceiveMarker(
        receiveMarkerScriptHash, oappCtrlAssetId, exit
      ),
      "marker pkScript not canonical"
    );

    let endpointIDGroup = tx.assetGroups.find(endpointIDAssetId);
    require(endpointIDGroup.sumOutputs == 1, "extra marker minted");
  }

  function send() {
    require(size(tx.packet(16)) == 183, "endpoint state packet size");
    require(size(tx.packet(19)) == 181, "lz send packet size");
    require(size(tx.inputs[1].packet(20)) == 175, "send invocation packet size");

    require(substr(tx.packet(16), 0, 1) == 1, "endpoint state version");
    require(substr(tx.packet(19), 0, 1) == 1, "lz send version");
    require(substr(tx.inputs[1].packet(20), 0, 1) == 1, "send invocation version");

    require(substr(tx.packet(16), 1, 32)  == endpointID, "wrong endpointID");
    require(substr(tx.packet(16), 33, 32) == oappID, "wrong oappID");
    require(bin2num(substr(tx.packet(16), 65, 4)) == remoteEID, "wrong remoteEID");
    require(substr(tx.packet(16), 69, 32) == remoteOApp, "wrong remoteOApp");

    require(substr(tx.packet(19), 1, 32)  == oappID, "lz send sender != oapp");
    require(bin2num(substr(tx.packet(19), 33, 4)) == remoteEID, "lz dstEID != remote");
    require(substr(tx.packet(19), 37, 32) == remoteOApp, "lz receiver != remoteOApp");

    require(substr(tx.inputs[1].packet(20), 1, 32)  == oappID, "invocation oappID mismatch");
    require(substr(tx.inputs[1].packet(20), 33, 32) == endpointID, "invocation endpointID mismatch");
    require(bin2num(substr(tx.inputs[1].packet(20), 67, 4)) == remoteEID, "invocation dstEID mismatch");
    require(substr(tx.inputs[1].packet(20), 71, 32) == remoteOApp, "invocation receiver mismatch");

    require(
      sha256(substr(tx.inputs[1].packet(20), 0, 175)) == substr(tx.packet(19), 77, 32),
      "lz send guid mismatch"
    );

    require(
      substr(tx.inputs[1].packet(20), 1, 32) == substr(tx.packet(19), 1, 32),
      "invocation/lzSend sender mismatch"
    );
    require(
      substr(tx.inputs[1].packet(20), 67, 4) == substr(tx.packet(19), 33, 4),
      "invocation/lzSend dstEID mismatch"
    );
    require(
      substr(tx.inputs[1].packet(20), 71, 32) == substr(tx.packet(19), 37, 32),
      "invocation/lzSend receiver mismatch"
    );
    require(
      substr(tx.inputs[1].packet(20), 103, 8) == substr(tx.packet(19), 109, 8),
      "invocation/lzSend amount mismatch"
    );
    require(
      substr(tx.inputs[1].packet(20), 111, 32) == substr(tx.packet(19), 117, 32),
      "invocation/lzSend remoteRecipient mismatch"
    );
    require(
      substr(tx.inputs[1].packet(20), 143, 32) == substr(tx.packet(19), 149, 32),
      "invocation/lzSend messageHash mismatch"
    );

    let oappIDGroup = tx.assetGroups.find(oappIDAssetId);
    require(oappIDGroup.sumInputs == 1, "send marker missing");
    require(oappIDGroup.sumOutputs == 0, "send marker not burned");

    require(
      tx.outputs[0].scriptPubKey == new Endpoint(
        endpointCtrlAssetId, endpointIDAssetId,
        oappCtrlAssetId,     oappIDAssetId,
        endpointID, oappID, remoteEID, remoteOApp,
        dvn0Pk, dvn1Pk, exit
      ),
      "endpoint state must continue"
    );
    require(
      tx.outputs[0].assets.lookup(endpointCtrlAssetId) == 1,
      "endpoint control missing on next state"
    );
  }
}
